# TurboWarp拓展开发教程

## 前言

TurboWarp是一个基于Scratch的现代化编程环境，它不仅提供了更快的执行速度，还支持自定义拓展功能。通过JavaScript开发拓展，我们可以为TurboWarp添加新的积木块、功能模块和交互方式。本文将详细介绍如何开发TurboWarp拓展。

## 什么是TurboWarp拓展

TurboWarp拓展是用JavaScript编写的插件，可以为TurboWarp编辑器添加新的功能。拓展可以包含：
- 自定义积木块（blocks）
- 新的变量和列表操作
- 外部API集成
- 硬件控制功能
- 游戏增强功能

## 开发环境准备

### 基础要求
1. 熟悉JavaScript编程
2. 了解TurboWarp/Scratch的基本概念
3. 文本编辑器（推荐VS Code）
4. 现代浏览器（用于测试）

### 项目结构
```
turbowarp-extension/
├── extension.js          # 拓展主文件
├── package.json         # 项目配置文件
└── README.md           # 说明文档
```

## 基础拓展开发

### 创建拓展文件

```javascript
(function(Scratch) {
  'use strict';

  class ExampleExtension {
    getInfo() {
      return {
        // 拓展ID，必须唯一
        id: 'exampleExtension',

        // 拓展显示名称
        name: '示例拓展',

        // 拓展颜色（可选）
        color1: '#FF6680',
        color2: '#FF4D6A',
        color3: '#FF3355',

        // 拓展菜单项
        menuIconURI: '', // 菜单图标URL

        // 拓展描述
        blocks: [
          {
            opcode: 'exampleBlock',
            blockType: Scratch.BlockType.COMMAND,
            text: '执行示例操作',
            arguments: {}
          },
          {
            opcode: 'getValue',
            blockType: Scratch.BlockType.REPORTER,
            text: '获取示例值',
            arguments: {}
          }
        ]
      };
    }

    // 实现积木块功能
    exampleBlock(args, util) {
      // 这里实现具体功能
      console.log('示例积木被执行');
    }

    getValue(args, util) {
      // 返回一个值
      return 'Hello TurboWarp!';
    }
  }

  // 注册拓展
  Scratch.extensions.register(new ExampleExtension());
})(Scratch);
```

### 项目配置文件

```json
{
  "name": "turbowarp-example-extension",
  "version": "1.0.0",
  "description": "TurboWarp示例拓展",
  "main": "extension.js",
  "scripts": {
    "test": "echo \"Error: no test specified\" && exit 1"
  },
  "keywords": [
    "turbowarp",
    "extension",
    "scratch"
  ],
  "author": "Your Name",
  "license": "MIT"
}
```

## 高级拓展功能

### 带参数的积木块

```javascript
(function(Scratch) {
  'use strict';

  class AdvancedExtension {
    getInfo() {
      return {
        id: 'advancedExtension',
        name: '高级拓展',
        color1: '#4CAF50',
        color2: '#45a049',
        color3: '#3d8b40',

        blocks: [
          // 带输入参数的命令积木
          {
            opcode: 'sayHello',
            blockType: Scratch.BlockType.COMMAND,
            text: '向 [NAME] 打招呼',
            arguments: {
              NAME: {
                type: Scratch.ArgumentType.STRING,
                defaultValue: '世界'
              }
            }
          },

          // 带多个参数的积木
          {
            opcode: 'calculate',
            blockType: Scratch.BlockType.REPORTER,
            text: '[A] 加 [B] 等于',
            arguments: {
              A: {
                type: Scratch.ArgumentType.NUMBER,
                defaultValue: 10
              },
              B: {
                type: Scratch.ArgumentType.NUMBER,
                defaultValue: 5
              }
            }
          },

          // 布尔值积木
          {
            opcode: 'isEven',
            blockType: Scratch.BlockType.BOOLEAN,
            text: '[NUMBER] 是偶数？',
            arguments: {
              NUMBER: {
                type: Scratch.ArgumentType.NUMBER,
                defaultValue: 4
              }
            }
          },

          // 下拉菜单积木
          {
            opcode: 'getDay',
            blockType: Scratch.BlockType.REPORTER,
            text: '获取 [DAY] 的信息',
            arguments: {
              DAY: {
                type: Scratch.ArgumentType.STRING,
                menu: 'days',
                defaultValue: 'monday'
              }
            }
          }
        ],

        // 下拉菜单定义
        menus: {
          days: {
            items: [
              {
                text: '星期一',
                value: 'monday'
              },
              {
                text: '星期二',
                value: 'tuesday'
              },
              {
                text: '星期三',
                value: 'wednesday'
              }
            ]
          }
        }
      };
    }

    // 实现积木功能
    sayHello(args, util) {
      const name = args.NAME;
      // 在TurboWarp中显示消息
      if (util.runtime.renderer) {
        // 可以在这里添加更多逻辑
        console.log(`Hello, ${name}!`);
      }
    }

    calculate(args, util) {
      const a = Number(args.A);
      const b = Number(args.B);
      return a + b;
    }

    isEven(args, util) {
      const number = Number(args.NUMBER);
      return number % 2 === 0;
    }

    getDay(args, util) {
      const day = args.DAY;
      const dayMap = {
        'monday': '星期一',
        'tuesday': '星期二',
        'wednesday': '星期三'
      };
      return dayMap[day] || '未知';
    }
  }

  Scratch.extensions.register(new AdvancedExtension());
})(Scratch);
```

## 实用拓展示例

### 数学计算拓展

```javascript
(function(Scratch) {
  'use strict';

  class MathExtension {
    getInfo() {
      return {
        id: 'mathExtension',
        name: '数学拓展',
        color1: '#2196F3',
        color2: '#1976D2',
        color3: '#0D47A1',

        blocks: [
          // 阶乘计算
          {
            opcode: 'factorial',
            blockType: Scratch.BlockType.REPORTER,
            text: '[NUMBER] 的阶乘',
            arguments: {
              NUMBER: {
                type: Scratch.ArgumentType.NUMBER,
                defaultValue: 5
              }
            }
          },

          // 随机数生成
          {
            opcode: 'randomRange',
            blockType: Scratch.BlockType.REPORTER,
            text: '在 [MIN] 到 [MAX] 之间的随机数',
            arguments: {
              MIN: {
                type: Scratch.ArgumentType.NUMBER,
                defaultValue: 1
              },
              MAX: {
                type: Scratch.ArgumentType.NUMBER,
                defaultValue: 100
              }
            }
          },

          // 质数判断
          {
            opcode: 'isPrime',
            blockType: Scratch.BlockType.BOOLEAN,
            text: '[NUMBER] 是质数？',
            arguments: {
              NUMBER: {
                type: Scratch.ArgumentType.NUMBER,
                defaultValue: 7
              }
            }
          },

          // 最大公约数
          {
            opcode: 'gcd',
            blockType: Scratch.BlockType.REPORTER,
            text: '[A] 和 [B] 的最大公约数',
            arguments: {
              A: {
                type: Scratch.ArgumentType.NUMBER,
                defaultValue: 12
              },
              B: {
                type: Scratch.ArgumentType.NUMBER,
                defaultValue: 18
              }
            }
          }
        ]
      };
    }

    factorial(args, util) {
      const n = Math.floor(Number(args.NUMBER));
      if (n < 0) return 0;
      if (n === 0 || n === 1) return 1;

      let result = 1;
      for (let i = 2; i <= n; i++) {
        result *= i;
      }
      return result;
    }

    randomRange(args, util) {
      const min = Number(args.MIN);
      const max = Number(args.MAX);
      return Math.floor(Math.random() * (max - min + 1)) + min;
    }

    isPrime(args, util) {
      const n = Math.floor(Number(args.NUMBER));
      if (n < 2) return false;
      if (n === 2) return true;
      if (n % 2 === 0) return false;

      for (let i = 3; i <= Math.sqrt(n); i += 2) {
        if (n % i === 0) return false;
      }
      return true;
    }

    gcd(args, util) {
      let a = Math.floor(Math.abs(Number(args.A)));
      let b = Math.floor(Math.abs(Number(args.B)));

      while (b !== 0) {
        let temp = b;
        b = a % b;
        a = temp;
      }
      return a;
    }
  }

  Scratch.extensions.register(new MathExtension());
})(Scratch);
```

## 网络请求拓展

### API集成拓展

```javascript
