(function(Scratch) {
  'use strict';

  class MathExtension {
    getInfo() {
      return {
        id: 'mathExtension',
        name: '数学拓展',
        color1: '#2196F3',
        color2: '#1976D2',
        color3: '#0D47A1',

        blocks: [
          // 阶乘计算
          {
            opcode: 'factorial',
            blockType: Scratch.BlockType.REPORTER,
            text: '[NUMBER] 的阶乘',
            arguments: {
              NUMBER: {
                type: Scratch.ArgumentType.NUMBER,
                defaultValue: 5
              }
            }
          },

          // 随机数生成
          {
            opcode: 'randomRange',
            blockType: Scratch.BlockType.REPORTER,
            text: '在 [MIN] 到 [MAX] 之间的随机数',
            arguments: {
              MIN: {
                type: Scratch.ArgumentType.NUMBER,
                defaultValue: 1
              },
              MAX: {
                type: Scratch.ArgumentType.NUMBER,
                defaultValue: 100
              }
            }
          },

          // 质数判断
          {
            opcode: 'isPrime',
            blockType: Scratch.BlockType.BOOLEAN,
            text: '[NUMBER] 是质数？',
            arguments: {
              NUMBER: {
                type: Scratch.ArgumentType.NUMBER,
                defaultValue: 7
              }
            }
          },

          // 最大公约数
          {
            opcode: 'gcd',
            blockType: Scratch.BlockType.REPORTER,
            text: '[A] 和 [B] 的最大公约数',
            arguments: {
              A: {
                type: Scratch.ArgumentType.NUMBER,
                defaultValue: 12
              },
              B: {
                type: Scratch.ArgumentType.NUMBER,
                defaultValue: 18
              }
            }
          }
        ]
      };
    }

    factorial(args, util) {
      const n = Math.floor(Number(args.NUMBER));
      if (n < 0) return 0;
      if (n === 0 || n === 1) return 1;

      let result = 1;
      for (let i = 2; i <= n; i++) {
        result *= i;
      }
      return result;
    }

    randomRange(args, util) {
      const min = Number(args.MIN);
      const max = Number(args.MAX);
      return Math.floor(Math.random() * (max - min + 1)) + min;
    }

    isPrime(args, util) {
      const n = Math.floor(Number(args.NUMBER));
      if (n < 2) return false;
      if (n === 2) return true;
      if (n % 2 === 0) return false;

      for (let i = 3; i <= Math.sqrt(n); i += 2) {
        if (n % i === 0) return false;
      }
      return true;
    }

    gcd(args, util) {
      let a = Math.floor(Math.abs(Number(args.A)));
      let b = Math.floor(Math.abs(Number(args.B)));

      while (b !== 0) {
        let temp = b;
        b = a % b;
        a = temp;
      }
      return a;
    }
  }

  Scratch.extensions.register(new MathExtension());
})(Scratch);
```

